import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Customer } from '../../core/models';

/** Customer detail. service_agent wires ApiService.getCustomer(id). */
@Component({
  selector: 'app-customer-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './customer-detail.component.html',
  styleUrl: './customer-detail.component.css',
})
export class CustomerDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly customer = signal<Customer | null>({
    id: 'c1',
    name: 'Northwind Traders',
    email: 'orders@northwind.example',
    phone: '+1 202 555 0180',
  });

  readonly canEdit = computed(() => this.auth.isSales());
  id = '';

  constructor(public auth: AuthService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    // service_agent: this.customer.set(await ApiService.getCustomer(this.id)).
  }
}
